mapper.select:
SELECT id, name, description, image, price, original_price AS originalPrice, discount, sales, rating, review_count AS reviewCount, stock, brand, spec, category_id AS categoryId, flash_sale_end_time AS flashSaleEndTime, enabled, created_at AS createdAt, updated_at AS updatedAt FROM t_product WHERE enabled = 1
AND category_id = #{categoryId}
ORDER BY id DESC
